previewCss:
.darma-loader-darma-custom-577 {color: var(--loader-color, #dc2626);
  --loader-secondary-color: var(--loader-secondary-color, #f97316);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 30px;
   aspect-ratio: 1;
   background: var(--loader-color, #dc2626);
   display: grid;
   animation: darma-loader-darma-custom-577-l4-0 1s infinite linear;
}
.darma-loader-darma-custom-577::before, .darma-loader-darma-custom-577::after  {
  content: "";
   grid-area: 1/1;
   background:var(--loader-color, #dc2626);
   animation: inherit;
   animation-name: darma-loader-darma-custom-577-l4-1;
}
.darma-loader-darma-custom-577::after  {
  background: var(--loader-color, #dc2626);
   --s: 60deg;
}
@keyframes darma-loader-darma-custom-577-l4-0  {
  0%,20% {transform: rotate(0)}
100% {transform: rotate(90deg)}
}
@keyframes darma-loader-darma-custom-577-l4-1  {
  50% {transform: rotate(var(--s,30deg))}
100% {transform: rotate(0)}
}

